	if err != nil {
		t.Fatalf("RunChildComplete duplicate error = %v", err)
	}
	if status.DeliveryID != loaded.ActiveChild.LastDeliveryID ||
		status.Wake.Mode != "suppress" ||
		status.Wake.Reason != "duplicate_delivery" {
		t.Fatalf("duplicate status = %+v", status)
	}
}

